__kernel void likelihood_kernel(
    __global double* arrayX,
    __global double* arrayY,
    __global double* xj,
    __global double* yj,
    __global double* CDF,
    __global int* ind,
    __global int* objxy,
    __global double* likelihood,
    __global unsigned char* I,
    __global double* u,
    __global double* weights,
    const int Nparticles,
    const int countOnes,
    const int max_size,
    const int k,
    const int IszY,
    const int Nfr,
    __global int* seed,
    __global double* partial_sums,
    __local double* local_sum)
{
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    // Update positions with noise
    int seed_idx = x;
    double u_val = fabs((double)(seed[seed_idx]) / ((double) 2147483647));
    seed[seed_idx] = (1103515245 * seed[seed_idx] + 12345) % 2147483647;
    double v_val = fabs((double)(seed[seed_idx]) / ((double) 2147483647));
    seed[seed_idx] = (1103515245 * seed[seed_idx] + 12345) % 2147483647;

    double cosine = cos(2.0 * 3.1415926535897932 * v_val);
    double rt = -2.0 * log(u_val);
    double noise_x = sqrt(rt) * cosine;

    u_val = fabs((double)(seed[seed_idx]) / ((double) 2147483647));
    seed[seed_idx] = (1103515245 * seed[seed_idx] + 12345) % 2147483647;
    v_val = fabs((double)(seed[seed_idx]) / ((double) 2147483647));
    seed[seed_idx] = (1103515245 * seed[seed_idx] + 12345) % 2147483647;

    cosine = cos(2.0 * 3.1415926535897932 * v_val);
    rt = -2.0 * log(u_val);
    double noise_y = sqrt(rt) * cosine;

    arrayX[x] += 1.0 + 5.0 * noise_x;
    arrayY[x] += -2.0 + 2.0 * noise_y;

    // Calculate indices and likelihood
    double likelihood_sum = 0.0;
    int base_idx = x * countOnes;

    for (int y = 0; y < countOnes; y++) {
        int indX = (int)(arrayX[x] + 0.5) + objxy[y * 2 + 1];
        int indY = (int)(arrayY[x] + 0.5) + objxy[y * 2];

        int pos = indX * IszY * Nfr + indY * Nfr + k;
        if (pos >= max_size) pos = 0;
        if (pos < 0) pos = 0;

        ind[base_idx + y] = pos;

        double val = (double)I[pos];
        likelihood_sum += ((val - 100.0) * (val - 100.0) - (val - 228.0) * (val - 228.0)) / 50.0;
    }

    likelihood[x] = likelihood_sum / ((double)countOnes);

    // Update weights
    weights[x] = weights[x] * exp(likelihood[x]);

    // Local sum for normalization
    local_sum[get_local_id(0)] = weights[x];
    for (int i = get_local_id(0) >> 1; i > 0; i >>= 1) {
        if ((get_local_id(0) & 1) == 0) {
            local_sum[get_local_id(0)] += local_sum[get_local_id(0) + i];
        }
    }

    if (get_local_id(0) == 0) {
        partial_sums[x] = local_sum[0];
    }
}

__kernel void sum_kernel(
    __global double* partial_sums,
    const int Nparticles)
{
    // This kernel is simplified as the sum is handled within likelihood_kernel via local memory
    // In a full implementation, this would aggregate partial_sums
    if (get_global_id(0) == 0) {
        double total = 0.0;
        for (int i = 0; i < Nparticles; i++) {
            total += partial_sums[i];
        }
        partial_sums[Nparticles] = total;
    }
}

__kernel void normalize_weights_kernel(
    __global double* weights,
    const int Nparticles,
    __global double* partial_sums,
    __global double* CDF,
    __global double* u,
    __global int* seed)
{
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    double sumWeights = partial_sums[Nparticles];
    if (sumWeights == 0.0) sumWeights = 1.0;

    weights[x] = weights[x] / sumWeights;

    // Build CDF
    if (x == 0) {
        CDF[0] = weights[0];
    } else {
        CDF[x] = weights[x] + CDF[x-1];
    }

    // Generate u values
    if (x == 0) {
        double u1 = (1.0 / ((double)Nparticles)) * fabs((double)(seed[0]) / ((double) 2147483647));
        seed[0] = (1103515245 * seed[0] + 12345) % 2147483647;
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + ((double)i) / ((double)Nparticles);
        }
    }
}

__kernel void find_index_kernel(
    __global double* arrayX,
    __global double* arrayY,
    __global double* CDF,
    __global double* u,
    __global double* xj,
    __global double* yj,
    __global double* weights,
    const int Nparticles)
{
    int j = get_global_id(0);
    if (j >= Nparticles) return;

    double value = u[j];
    int index = -1;

    // Binary search for index
    int beginIndex = 0;
    int endIndex = Nparticles - 1;

    while (beginIndex <= endIndex) {
        int middleIndex = beginIndex + ((endIndex - beginIndex) / 2);

        if (CDF[middleIndex] >= value) {
            if (middleIndex == 0 || CDF[middleIndex - 1] < value) {
                index = middleIndex;
                break;
            } else if (CDF[middleIndex - 1] == value) {
                int temp = middleIndex;
                while (temp > 0 && CDF[temp - 1] == value) {
                    temp--;
                }
                index = temp;
                break;
            } else {
                endIndex = middleIndex - 1;
            }
        } else {
            beginIndex = middleIndex + 1;
        }
    }

    if (index == -1) {
        index = Nparticles - 1;
    }

    xj[j] = arrayX[index];
    yj[j] = arrayY[index];

    // Reset for next iteration
    arrayX[j] = xj[j];
    arrayY[j] = yj[j];
    weights[j] = 1.0 / ((double)Nparticles);
}
